class RateLimiter:
    def __init__(self):
        self._hits: dict[str, deque[float]] = defaultdict(deque)
        self._lock = threading.Lock()

    def hit(self, key: str, limit: int, window_seconds: int):
        now = time.monotonic()
        with self._lock:
            q = self._hits[key]
            while q and now - q[0] >= window_seconds:
                q.popleft()
            if len(q) >= limit:
                retry = max(1, math.ceil(window_seconds - (now - q[0])))
                raise APIProblem(
                    429,
                    [error("request", "rate_limited", "Too many registration attempts.")],
                    {"Retry-After": str(retry)},
                )
            q.append(now)


